@@ -0,0 +1,292 @@
+export type Provider = "openai" | "anthropic";
+export type Locale = "en" | "zh";
+
+export type MessageRole = "system" | "user" | "assistant";
+
+export type ChatMessage = {
+  role: MessageRole;
+  content: string;
+};
+
+export type ProviderSettings = {
+  id: string;
+  name: string;
+  provider: Provider;
+  apiKey: string;
+  baseUrl?: string;
+  models: string[];
+  defaultModel: string;
+  enabled: boolean;
+};
+
+export type ModelUsage = {
+  inputTokens?: number;
+  outputTokens?: number;
+  totalTokens?: number;
+};
+
+export type ModelRequest = {
+  messages: ChatMessage[];
+  model?: string;
+  maxTokens?: number;
+  temperature?: number;
+  timeoutMs?: number;
+};
+
+export type ModelResponse = {
+  provider: Provider;
+  model: string;
+  text: string;
+  usage?: ModelUsage;
+  raw?: unknown;
+};
+
+export type ModelGateway = {
+  chat(messages: ChatMessage[]): Promise<ModelResponse>;
+};
+
+export type Scope = "model.chat" | "page.read" | "page.act" | "agent.run" | "debugger.control";
+export type AgentControlMode = "dom" | "debugger" | "auto";
+export type AgentTaskIntent = "memory" | "chat" | "run";
+
+export type SitePermission = {
+  origin: string;
+  appName?: string;
+  scopes: Scope[];
+  autoRun: boolean;
+  createdAt: string;
+  updatedAt: string;
+  lastUsedAt?: string;
+  revokedAt?: string;
+};
+
+export type CallSource = "sidebar" | "gateway";
+export type CallType = "access" | "chat" | "run";
+export type CallStatus = "success" | "failed" | "denied" | "canceled" | "revoked";
+
+export type CallLog = {
+  id: string;
+  source: CallSource;
+  origin?: string;
+  type: CallType;
+  model?: string;
+  status: CallStatus;
+  createdAt: string;
+  summary?: string;
+};
+
+export type DebugLog = {
+  id: string;
+  callId?: string;
+  createdAt: string;
+  title: string;
+  details: unknown;
+};
+
+export type GatewaySettings = {
+  enabled: boolean;
+};
+
+export type ExtensionSettings = {
+  locale: Locale;
+  providers: ProviderSettings[];
+  defaultProviderId?: string;
+  defaultModel?: string;
+  gateway: GatewaySettings;
+  skills: InstalledSkill[];
+  permissions: SitePermission[];
+  callLogs: CallLog[];
+  debugLogs: DebugLog[];
+};
+
+export type InteractiveElement = {
+  selector: string;
+  tagName: string;
+  label: string;
+  role?: string;
+};
+
+export type DomObservation = {
+  title: string;
+  url: string;
+  origin: string;
+  text: string;
+  selectedText?: string;
+  headings: string[];
+  links: Array<{ text: string; href: string }>;
+  interactiveElements: InteractiveElement[];
+};
+
+export type ConversationMemoryTurn = {
+  role: "user" | "assistant";
+  content: string;
+};
+
+export type ConversationMemory = {
+  turns: ConversationMemoryTurn[];
+};
+
+export type DomAction =
+  | { type: "click"; selector: string }
+  | { type: "type"; selector: string; value: string }
+  | { type: "scroll"; direction: "up" | "down"; amount?: number };
+
+export type AgentReadAction = { type: "read" };
+export type AgentDebuggerAction = { type: "debugger"; reason?: string };
+export type AgentSkillAction = { type: "skill"; skillId: string; input?: Record<string, unknown> };
+export type AgentAction = DomAction | AgentReadAction | AgentDebuggerAction | AgentSkillAction;
+export type AgentActionStatus = "success" | "failed" | "needs_confirmation" | "blocked";
+
+export type DomActionResult = {
+  ok: boolean;
+  status?: AgentActionStatus;
+  message: string;
+  skillDraft?: InstalledSkill;
+};
+
+export type DebuggerSnapshot = DomObservation & {
+  source: "debugger";
+  document?: unknown;
+  accessibilityTree?: unknown[];
+};
+
+export type DebuggerAction =
+  | { type: "attach" }
+  | { type: "detach" }
+  | { type: "snapshot" }
+  | { type: "screenshot"; fullPage?: boolean }
+  | { type: "click"; x: number; y: number }
+  | { type: "click"; selector: string }
+  | { type: "type"; text: string; selector?: string }
+  | { type: "scroll"; direction: "up" | "down"; amount?: number }
+  | { type: "wait"; ms?: number };
+
+export type DebuggerActionResult = {
+  ok: boolean;
+  message: string;
+  observation?: DebuggerSnapshot;
+  screenshot?: PageScreenshot;
+  rewrite?: PageRewriteResult;
+  formFill?: FormFillResult;
+};
+
+export type PageScreenshot = {
+  dataUrl: string;
+  mimeType: "image/png";
+  width: number;
+  height: number;
+  filename: string;
+};
+
+export type PageTextReplacement = {
+  index: number;
+  original: string;
+  replacement: string;
+};
+
+export type PageRewriteResult = {
+  sessionId: string;
+  changed: number;
+  replacements: PageTextReplacement[];
+};
+
+export type FormFillField = {
+  selector: string;
+  value: string;
+};
+
+export type FormFillResult = {
+  filled: number;
+  skipped: Array<{ selector: string; reason: string }>;
+};
+
+export type BenchmarkToolRequest =
+  | { type: "screenshot" }
+  | { type: "report" }
+  | { type: "rewrite"; instruction: string }
+  | { type: "restore-rewrite"; sessionId?: string }
+  | { type: "fill-form"; instruction: string };
+
+export type InstalledSkill = {
+  id: string;
+  name: string;
+  description: string;
+  skillMarkdown: string;
+  enabled: boolean;
+  source: "builtin" | "skills.sh" | "manual";
+  sourceUrl?: string;
+  installedAt?: string;
+  updatedAt?: string;
+};
+
+export type BenchmarkToolResult =
+  | { type: "screenshot"; title: string; screenshot: PageScreenshot }
+  | { type: "report"; title: string; html: string }
+  | { type: "rewrite"; title: string; rewrite: PageRewriteResult }
+  | { type: "restore-rewrite"; title: string; restored: number }
+  | { type: "fill-form"; title: string; formFill: FormFillResult };
+
+export type AgentEvent =
+  | { type: "observe"; observation: DomObservation }
+  | { type: "thought"; text: string; confidence?: number }
+  | { type: "plan"; text: string; confidence?: number }
+  | { type: "action"; action: AgentAction; reason: string; confidence?: number }
+  | { type: "action-result"; action: AgentAction; result: DomActionResult }
+  | { type: "blocked"; reason: string; status: "needs_confirmation" | "blocked" }
+  | { type: "final"; text: string };
+
+export type GatewayErrorCode =
+  | "permission_denied"
+  | "model_not_configured"
+  | "user_rejected"
+  | "gateway_disabled"
+  | "page_unavailable"
+  | "page_not_operable"
+  | "debugger_control_unavailable"
+  | "invalid_request"
+  | "internal_error";
+
+export type GatewayMethod = "requestAccess" | "getStatus" | "chat" | "run" | "models.list";
+
+export type BrowserAgentRequest =
+  | { id: string; requestId: string; source: "agenticify-page"; version: "1"; method: "requestAccess"; payload: AccessRequestPayload }
+  | { id: string; requestId: string; source: "agenticify-page"; version: "1"; method: "getStatus"; payload?: undefined }
+  | { id: string; requestId: string; source: "agenticify-page"; version: "1"; method: "chat"; payload: ChatPayload }
+  | { id: string; requestId: string; source: "agenticify-page"; version: "1"; method: "run"; payload: RunPayload }
+  | { id: string; requestId: string; source: "agenticify-page"; version: "1"; method: "models.list"; payload?: undefined };
+
+export type GatewayError = {
+  code: GatewayErrorCode;
+  message: string;
+  details?: unknown;
+};
+
+export type BrowserAgentResponse =
+  | { id: string; requestId: string; source: "agenticify-extension"; ok: true; result: unknown }
+  | { id: string; requestId: string; source: "agenticify-extension"; ok: false; code: GatewayErrorCode; error: GatewayError };
+
+export type AccessRequestPayload = {
+  appName?: string;
+  scopes: Scope[];
+  reason?: string;
+  autoRun?: boolean;
+};
+
+export type PendingAccessRequest = {
+  id: string;
+  origin: string;
+  appName?: string;
+  scopes: Scope[];
+  reason?: string;
+  requestedAutoRun: boolean;
+  createdAt: string;
+};
+
+export type ChatPayload = {
+  messages: ChatMessage[];
+};
+
+export type RunPayload = {
+  task: string;
+  mode?: AgentControlMode;
+};

diff --git a/src/agent/runtime.ts b/src/agent/runtime.ts
new file mode 100644
index 0000000..26a3cf1
--- /dev/null
+++ b/src/agent/runtime.ts
@@ -0,0 +1,283 @@
+import type {
+  AgentAction,
+  AgentControlMode,
+  AgentTaskIntent,
+  AgentEvent,
+  ChatMessage,
+  ConversationMemory,
+  DomActionResult,
+  DomObservation,
+  InstalledSkill,
+  ModelGateway
+} from "../shared/types";
+import { buildSkillPrompt, matchSkillsForTask } from "./skills";
+
+type RunAgentTaskInput = {
+  task: string;
+  observe: () => Promise<DomObservation>;
+  act?: (action: AgentAction) => Promise<DomActionResult>;
+  modelGateway: ModelGateway;
+  maxSteps?: number;
+  mode?: AgentControlMode;
+  skills?: InstalledSkill[];
+};
+
+type RunPageChatInput = {
+  task: string;
+  observation: DomObservation;
+  modelGateway: ModelGateway;
+  memory?: ConversationMemory;
+};
+
+type RunMemoryChatInput = {
+  task: string;
+  modelGateway: ModelGateway;
+  memory?: ConversationMemory;
+};
+
+type AgentResult = {
+  finalText: string;
+  events: AgentEvent[];
+};
+
+type ModelDecision = {
+  thought?: string;
+  plan?: string;
+  action?: AgentAction;
+  final?: string;
+  reason?: string;
+  confidence?: number;
+};
+
+const MAX_STEPS = 5;
+
+export function classifyTaskIntent(task: string): AgentTaskIntent {
+  const text = task.toLowerCase();
+  if (/\b(remember|memorize|note|keep in mind)\b/.test(text) || /(记住|记一下|帮我记|记得)/.test(task)) {
+    return "memory";
+  }
+  if (/\b(click|type|fill|submit|scroll|open|select|choose|press|install|create skill|rewrite|translate|screenshot|capture|report|export|delete|buy|purchase|pay)\b/.test(text)) {
+    return "run";
+  }
+  if (/(点击|填写|提交|滚动|打开|选择|安装|创建.*skill|创建.*技能|改写|翻译|截图|报告|导出|删除|购买|支付)/.test(task)) {
+    return "run";
+  }
+  return "chat";
+}
+
+function extractJsonObject(text: string): string | undefined {
+  const fenced = /```(?:json)?\s*([\s\S]*?)```/i.exec(text);
+  const candidate = fenced?.[1]?.trim() ?? text.trim();
+  if (candidate.startsWith("{") && candidate.endsWith("}")) return candidate;
+
+  const start = candidate.indexOf("{");
+  if (start === -1) return undefined;
+
+  let depth = 0;
+  let inString = false;
+  let escaped = false;
+  for (let index = start; index < candidate.length; index += 1) {
+    const char = candidate[index];
+    if (escaped) {
+      escaped = false;
+      continue;
+    }
+    if (char === "\\") {
+      escaped = true;
+      continue;
+    }
+    if (char === "\"") {
+      inString = !inString;
+      continue;
+    }
+    if (inString) continue;
+    if (char === "{") depth += 1;
+    if (char === "}") {
+      depth -= 1;
+      if (depth === 0) return candidate.slice(start, index + 1);
+    }
+  }
+
+  return undefined;
+}
+
+function normalizeDecision(value: unknown, fallbackText: string): ModelDecision {
+  if (!value || typeof value !== "object") return { final: fallbackText };
+  const decision = value as ModelDecision;
+  const hasFinal = typeof decision.final === "string";
+  const hasAction = Boolean(decision.action && typeof decision.action === "object");
+  if (!hasFinal && !hasAction) return { final: fallbackText };
+  return decision;
+}
+
+function parseDecision(text: string): ModelDecision {
+  const json = extractJsonObject(text);
+  if (!json) return { final: text };
+
+  try {
+    return normalizeDecision(JSON.parse(json), text);
+  } catch {
+    return { final: text };
+  }
+}
+
+function isHighRiskAction(task: string, action: AgentAction): boolean {
+  if (action.type !== "click") return false;
+  return /\b(buy|purchase|pay|submit|delete|remove|confirm|checkout)\b/i.test(`${task} ${action.selector}`);
+}
+
+function buildMessages(task: string, observation: DomObservation, events: AgentEvent[], maxSteps: number, mode: AgentControlMode, skills: InstalledSkill[]): ChatMessage[] {
+  const skillPrompt = buildSkillPrompt(skills);
+  return [
+    {
